package com.budgetalert.coverageservice.controller; import com.budgetalert.coverageservice.dto.CoverageResponse; import com.budgetalert.coverageservice.service.CoverageService; import lombok.RequiredArgsConstructor; import org.springframework.web.bind.annotation.*; import java.util.*; @RestController @RequestMapping("/api/v1/coverage") @RequiredArgsConstructor public class CoverageController { private final CoverageService coverageService; @PostMapping("/calculate") public List<CoverageResponse> calculateNow(){ return coverageService.calculateDailyCoverage(); } @GetMapping("/projects/{projectId}") public List<CoverageResponse> getCoverage(@PathVariable String projectId){ return coverageService.getCoverageByProject(projectId); } }